    \draw[thick] (0,0) rectangle (6,4);
    \draw[gray!45] (2,0) -- (2,4);
    \draw[gray!45] (4,0) -- (4,4);
    \draw[gray!45] (0,2) -- (6,2);

    \foreach \x/\y/\d in {
        1/1/2.0,
        3/1/2.3,
        5/1/2.6,
        1/3/2.4,
        3/3/2.8,
        5/3/3.1
    } {
        \fill (\x,\y) circle (2pt);
        \node[above] at (\x,\y) {\(\d\)};
    }

    \node at (3,-0.85) {density samples at cell centers};
\end{tikzpicture}

\begin{tikzpicture}[scale=0.85, >=stealth]
